from dataclasses import dataclass
from typing import Any


@dataclass
class VectorChunk:
    """Represents one chunk returned from a vector store with its metadata."""
    chunk_id: str
    text: str
    metadata: dict[str, Any]  # must contain 'sensitivity_label'


def label_from_chunk(chunk: VectorChunk) -> SensitivityLabel:
    """Extract and validate the sensitivity label stored in chunk metadata."""
    raw = chunk.metadata.get("sensitivity_label")
    if raw is None:
        # Unlabeled data is treated as RESTRICTED until explicitly classified.
        return SensitivityLabel.RESTRICTED
    try:
        return SensitivityLabel[raw.upper().replace(" ", "_")]
    except KeyError:
        raise ValueError(
            f"Unknown sensitivity label '{raw}' in chunk '{chunk.chunk_id}'. "
            "Verify the vector store metadata schema."
        )


